import{_ as t,o as s,c as e,a4 as n}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"语法详解","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Learn-Detail-002-语法详解-V1.0-20260405.md","filePath":"english/Eng-Learn-Detail-002-语法详解-V1.0-20260405.md"}'),i={name:"english/Eng-Learn-Detail-002-语法详解-V1.0-20260405.md"};function l(p,a,o,d,h,r){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="语法详解" tabindex="-1">语法详解 <a class="header-anchor" href="#语法详解" aria-label="Permalink to &quot;语法详解&quot;">​</a></h1><p><strong>从规则到工具——构建句子的骨架</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>掌握非谓语动词的用法（不定式、动名词、分词）</li><li>熟练运用各类从句（定语从句、名词性从句、状语从句）</li><li>理解特殊句式（倒装、强调、虚拟语气）</li><li>能够分析长难句结构</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>语法体系</span></span>
<span class="line"><span>├── 非谓语动词 ⭐</span></span>
<span class="line"><span>│   ├── 不定式(to do)</span></span>
<span class="line"><span>│   ├── 动名词(doing)</span></span>
<span class="line"><span>│   ├── 现在分词(doing)</span></span>
<span class="line"><span>│   └── 过去分词(done)</span></span>
<span class="line"><span>├── 从句 ⭐</span></span>
<span class="line"><span>│   ├── 定语从句</span></span>
<span class="line"><span>│   ├── 名词性从句</span></span>
<span class="line"><span>│   └── 状语从句</span></span>
<span class="line"><span>├── 特殊句式 ⭐</span></span>
<span class="line"><span>│   ├── 倒装句</span></span>
<span class="line"><span>│   ├── 强调句</span></span>
<span class="line"><span>│   └── 虚拟语气</span></span>
<span class="line"><span>└── 长难句分析</span></span></code></pre></div><hr><h2 id="二、非谓语动词-⭐" tabindex="-1">二、非谓语动词 ⭐ <a class="header-anchor" href="#二、非谓语动词-⭐" aria-label="Permalink to &quot;二、非谓语动词 ⭐&quot;">​</a></h2><h3 id="_2-1-不定式-to-do" tabindex="-1">2.1 不定式 (to do) <a class="header-anchor" href="#_2-1-不定式-to-do" aria-label="Permalink to &quot;2.1 不定式 (to do)&quot;">​</a></h3><p><strong>作主语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>To learn English well is important.</span></span>
<span class="line"><span>= It is important to learn English well.（形式主语）</span></span></code></pre></div><p><strong>作宾语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want to go home.</span></span>
<span class="line"><span>I decide to study abroad.</span></span></code></pre></div><p><strong>作宾补</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I want you to help me.</span></span>
<span class="line"><span>The teacher told us to finish the homework.</span></span></code></pre></div><p><strong>作定语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I have a lot of work to do.</span></span>
<span class="line"><span>He is always the first to come.</span></span></code></pre></div><p><strong>作状语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目的：I came here to see you.</span></span>
<span class="line"><span>结果：He woke up to find everyone gone.</span></span>
<span class="line"><span>原因：I&#39;m glad to see you.</span></span></code></pre></div><p><strong>省略to的情况</strong>：</p><ul><li>使役动词：make/let/have sb. do sth.</li><li>感官动词：see/watch/hear/notice sb. do sth.</li></ul><h3 id="_2-2-动名词-doing" tabindex="-1">2.2 动名词 (doing) <a class="header-anchor" href="#_2-2-动名词-doing" aria-label="Permalink to &quot;2.2 动名词 (doing)&quot;">​</a></h3><p><strong>作主语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swimming is good exercise.</span></span>
<span class="line"><span>Reading aloud is helpful.</span></span></code></pre></div><p><strong>作宾语</strong>（接动名词的动词）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enjoy doing 喜欢做</span></span>
<span class="line"><span>finish doing 完成做</span></span>
<span class="line"><span>practise doing 练习做</span></span>
<span class="line"><span>consider doing 考虑做</span></span>
<span class="line"><span>suggest doing 建议做</span></span>
<span class="line"><span>avoid doing 避免做</span></span>
<span class="line"><span>keep doing 持续做</span></span>
<span class="line"><span>mind doing 介意做</span></span></code></pre></div><p><strong>作表语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>My hobby is reading.</span></span>
<span class="line"><span>His job is teaching.</span></span></code></pre></div><h3 id="_2-3-分词" tabindex="-1">2.3 分词 <a class="header-anchor" href="#_2-3-分词" aria-label="Permalink to &quot;2.3 分词&quot;">​</a></h3><p><strong>现在分词 (doing)</strong>：</p><ul><li>主动、进行</li><li>作定语：a sleeping baby</li><li>作状语：Walking in the park, I met an old friend.</li><li>作宾补：I found him reading in the library.</li></ul><p><strong>过去分词 (done)</strong>：</p><ul><li>被动、完成</li><li>作定语：a broken cup</li><li>作状语：Seen from the hill, the city looks beautiful.</li><li>作宾补：I had my hair cut yesterday.</li></ul><h3 id="_2-4-非谓语动词选择判断" tabindex="-1">2.4 非谓语动词选择判断 <a class="header-anchor" href="#_2-4-非谓语动词选择判断" aria-label="Permalink to &quot;2.4 非谓语动词选择判断&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">情况</th><th style="text-align:left;">形式</th></tr></thead><tbody><tr><td style="text-align:center;">表目的</td><td style="text-align:left;">to do</td></tr><tr><td style="text-align:center;">表进行/主动</td><td style="text-align:left;">doing</td></tr><tr><td style="text-align:center;">表完成/被动</td><td style="text-align:left;">done</td></tr><tr><td style="text-align:center;">介词后</td><td style="text-align:left;">doing</td></tr></tbody></table><hr><h2 id="三、从句-⭐" tabindex="-1">三、从句 ⭐ <a class="header-anchor" href="#三、从句-⭐" aria-label="Permalink to &quot;三、从句 ⭐&quot;">​</a></h2><h3 id="_3-1-定语从句" tabindex="-1">3.1 定语从句 <a class="header-anchor" href="#_3-1-定语从句" aria-label="Permalink to &quot;3.1 定语从句&quot;">​</a></h3><p><strong>关系代词</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">先行词</th><th style="text-align:center;">主语</th><th style="text-align:center;">宾语</th><th style="text-align:center;">定语</th></tr></thead><tbody><tr><td style="text-align:center;">人</td><td style="text-align:center;">who/that</td><td style="text-align:center;">who/whom/that/省略</td><td style="text-align:center;">whose</td></tr><tr><td style="text-align:center;">物</td><td style="text-align:center;">which/that</td><td style="text-align:center;">which/that/省略</td><td style="text-align:center;">whose/of which</td></tr></tbody></table><p><strong>关系副词</strong>：</p><ul><li>when（表时间）</li><li>where（表地点）</li><li>why（表原因）</li></ul><p><strong>注意</strong>：</p><ul><li>that不能引导非限制性定语从句</li><li>介词后指人用whom，指物用which</li></ul><h3 id="_3-2-名词性从句" tabindex="-1">3.2 名词性从句 <a class="header-anchor" href="#_3-2-名词性从句" aria-label="Permalink to &quot;3.2 名词性从句&quot;">​</a></h3><p><strong>主语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What he said is true.</span></span>
<span class="line"><span>Whether he will come is uncertain.</span></span></code></pre></div><p><strong>宾语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I know that he is right.</span></span>
<span class="line"><span>I don&#39;t know what he wants.</span></span></code></pre></div><p><strong>表语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The problem is that we don&#39;t have enough time.</span></span></code></pre></div><p><strong>同位语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The news that he won the game excited us.</span></span>
<span class="line"><span>（that不省略，只起连接作用）</span></span></code></pre></div><h3 id="_3-3-状语从句" tabindex="-1">3.3 状语从句 <a class="header-anchor" href="#_3-3-状语从句" aria-label="Permalink to &quot;3.3 状语从句&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:left;">连词</th></tr></thead><tbody><tr><td style="text-align:center;">时间</td><td style="text-align:left;">when, while, as, before, after, since, until</td></tr><tr><td style="text-align:center;">地点</td><td style="text-align:left;">where, wherever</td></tr><tr><td style="text-align:center;">原因</td><td style="text-align:left;">because, since, as</td></tr><tr><td style="text-align:center;">条件</td><td style="text-align:left;">if, unless, as long as</td></tr><tr><td style="text-align:center;">让步</td><td style="text-align:left;">although, though, even if</td></tr><tr><td style="text-align:center;">目的</td><td style="text-align:left;">so that, in order that</td></tr><tr><td style="text-align:center;">结果</td><td style="text-align:left;">so...that, such...that</td></tr></tbody></table><hr><h2 id="四、特殊句式-⭐" tabindex="-1">四、特殊句式 ⭐ <a class="header-anchor" href="#四、特殊句式-⭐" aria-label="Permalink to &quot;四、特殊句式 ⭐&quot;">​</a></h2><h3 id="_4-1-倒装句" tabindex="-1">4.1 倒装句 <a class="header-anchor" href="#_4-1-倒装句" aria-label="Permalink to &quot;4.1 倒装句&quot;">​</a></h3><p><strong>完全倒装</strong>（谓语全部提前）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Here comes the bus.</span></span>
<span class="line"><span>Out rushed the children.</span></span></code></pre></div><p><strong>部分倒装</strong>（助动词提前）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>否定词开头：Never have I seen such a beautiful place.</span></span>
<span class="line"><span>Only开头：Only in this way can we solve the problem.</span></span>
<span class="line"><span>So...that：So fast does he run that I can&#39;t catch up.</span></span></code></pre></div><h3 id="_4-2-强调句" tabindex="-1">4.2 强调句 <a class="header-anchor" href="#_4-2-强调句" aria-label="Permalink to &quot;4.2 强调句&quot;">​</a></h3><p><strong>结构</strong>：It is/was + 被强调部分 + that/who...</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原句：I met Tom in the park yesterday.</span></span>
<span class="line"><span>强调主语：It was I who/that met Tom in the park yesterday.</span></span>
<span class="line"><span>强调宾语：It was Tom who/that I met in the park yesterday.</span></span>
<span class="line"><span>强调地点：It was in the park that I met Tom yesterday.</span></span>
<span class="line"><span>强调时间：It was yesterday that I met Tom in the park.</span></span></code></pre></div><h3 id="_4-3-虚拟语气" tabindex="-1">4.3 虚拟语气 <a class="header-anchor" href="#_4-3-虚拟语气" aria-label="Permalink to &quot;4.3 虚拟语气&quot;">​</a></h3><p><strong>与现在相反</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If I were you, I would take the job.</span></span>
<span class="line"><span>（从句：did/were，主句：would/could/should/might do）</span></span></code></pre></div><p><strong>与过去相反</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If I had known the truth, I would have told you.</span></span>
<span class="line"><span>（从句：had done，主句：would/could/should/might have done）</span></span></code></pre></div><p><strong>与将来相反</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If I should/were to see him, I would tell him.</span></span>
<span class="line"><span>（从句：should do/were to do，主句：would do）</span></span></code></pre></div><hr><h2 id="五、长难句分析" tabindex="-1">五、长难句分析 <a class="header-anchor" href="#五、长难句分析" aria-label="Permalink to &quot;五、长难句分析&quot;">​</a></h2><h3 id="分析步骤" tabindex="-1">分析步骤 <a class="header-anchor" href="#分析步骤" aria-label="Permalink to &quot;分析步骤&quot;">​</a></h3><ol><li><strong>找谓语动词</strong>（确定句子数量）</li><li><strong>找连词</strong>（确定从句类型）</li><li><strong>划分主干</strong>（主谓宾/主系表）</li><li><strong>识别修饰成分</strong>（定语、状语、同位语）</li></ol><h3 id="示例分析" tabindex="-1">示例分析 <a class="header-anchor" href="#示例分析" aria-label="Permalink to &quot;示例分析&quot;">​</a></h3><p><strong>例句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The book that I borrowed from the library yesterday is very interesting.</span></span></code></pre></div><p><strong>分析</strong>：</p><ul><li>谓语1：borrowed（定语从句中）</li><li>谓语2：is（主句）</li><li>主干：The book is very interesting.</li><li>定语从句：that I borrowed from the library yesterday（修饰book）</li></ul><p><strong>翻译</strong>：我昨天从图书馆借的那本书很有趣。</p><hr><h2 id="六、配套练习" tabindex="-1">六、配套练习 <a class="header-anchor" href="#六、配套练习" aria-label="Permalink to &quot;六、配套练习&quot;">​</a></h2><h3 id="练习1-选择正确的非谓语形式" tabindex="-1">练习1：选择正确的非谓语形式 <a class="header-anchor" href="#练习1-选择正确的非谓语形式" aria-label="Permalink to &quot;练习1：选择正确的非谓语形式&quot;">​</a></h3><ol><li>I enjoy ______ (read) novels.</li><li>He told me ______ (finish) the work on time.</li><li>______ (see) from the top, the city is beautiful.</li></ol><p><strong>答案</strong>：1. reading 2. to finish 3. Seen</p><h3 id="练习2-完成句子" tabindex="-1">练习2：完成句子 <a class="header-anchor" href="#练习2-完成句子" aria-label="Permalink to &quot;练习2：完成句子&quot;">​</a></h3><ol><li><p>我认识的第一个人是李华。（定语从句） The first person ______ was Li Hua.</p></li><li><p>重要的是我们要努力学习。（主语从句） ______ is ______ we study hard.</p></li></ol><p><strong>答案</strong>：</p><ol><li>(that) I knew</li><li>What; that</li></ol><hr><p><strong>文档编号</strong>: Eng-Learn-Detail-002<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,96)])])}const u=t(i,[["render",l]]);export{g as __pageData,u as default};
